package org.example.apigateway.filter;

import org.example.apigateway.config.ApiKeyAuthenticationManager;
import org.example.apigateway.config.ApiKeyAuthenticationToken;
import org.springframework.http.HttpHeaders;
import org.springframework.http.server.reactive.ServerHttpRequest;
import org.springframework.security.authentication.AbstractAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.web.server.authentication.AuthenticationWebFilter;
import org.springframework.web.server.ServerWebExchange;
import reactor.core.publisher.Mono;

public class ApiKeyAuthenticationFilter extends AuthenticationWebFilter {

    public ApiKeyAuthenticationFilter(ApiKeyAuthenticationManager manager) {
        super(manager);

        setServerAuthenticationConverter(exchange -> {
            ServerHttpRequest request = exchange.getRequest();
            String apiKey = request.getHeaders().getFirst("x-api-key");

            if (apiKey == null) {
                return Mono.empty();
            }

            AbstractAuthenticationToken token = new ApiKeyAuthenticationToken(apiKey, "UNKNOWN");
            return Mono.just(token);
        });
    }
}

package org.example.apigateway.filter;

import org.example.apigateway.config.ApiKeyAuthenticationManager;
import org.example.apigateway.config.ApiKeyAuthenticationToken;
import org.springframework.http.HttpHeaders;
import org.springframework.http.server.reactive.ServerHttpRequest;
import org.springframework.security.authentication.AbstractAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.web.server.authentication.AuthenticationWebFilter;
import org.springframework.web.server.ServerWebExchange;
import reactor.core.publisher.Mono;

public class ApiKeyAuthenticationFilter extends AuthenticationWebFilter {

    public ApiKeyAuthenticationFilter(ApiKeyAuthenticationManager manager) {
        super(manager);

        setServerAuthenticationConverter(exchange -> {
            ServerHttpRequest request = exchange.getRequest();
            String apiKey = request.getHeaders().getFirst("x-api-key");

            if (apiKey == null || apiKey.trim().isEmpty()) {
                return Mono.empty();
            }

            // Kreiraj privremeni token sa API key-om kao credentials
            // Manager će onda da proveri key i doda pravi role
            AbstractAuthenticationToken token = new ApiKeyAuthenticationToken(apiKey, "");
            return Mono.just(token);
        });
    }
}

package org.example.apigateway.config;

import org.springframework.security.authentication.AbstractAuthenticationToken;
import java.util.Collections;

public class ApiKeyAuthenticationToken extends AbstractAuthenticationToken {

    private final String apiKey;
    private final String role;

    public ApiKeyAuthenticationToken(String apiKey, String role) {
        super(Collections.singleton(() -> role));
        this.apiKey = apiKey;
        this.role = role;
        setAuthenticated(true);
    }

    @Override
    public Object getCredentials() {
        return apiKey;
    }

    @Override
    public Object getPrincipal() {
        return role;
    }
}

package org.example.apigateway.config;

import org.springframework.security.authentication.AbstractAuthenticationToken;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import java.util.Collections;
import java.util.List;

public class ApiKeyAuthenticationToken extends AbstractAuthenticationToken {

    private final String apiKey;
    private final String role;

    public ApiKeyAuthenticationToken(String apiKey, String role) {
        super(role != null && !role.isEmpty() 
            ? List.of(new SimpleGrantedAuthority(role)) 
            : Collections.emptyList());
        this.apiKey = apiKey;
        this.role = role;
        setAuthenticated(!role.isEmpty());
    }

    @Override
    public Object getCredentials() {
        return apiKey;
    }

    @Override
    public Object getPrincipal() {
        return role;
    }
}
